/**
 * @fileoverview GridTable Feature — Multi-level (expandable) rows mixin.
 *
 * Lazy-loaded when `subRow: fn` is set in config.
 * Adds expand/collapse toggles and child-row interleaving.
 *
 * @module module/GridTable/features/multilevel
 */

import { remapExpandedRows } from '../helpers.js';
import { rebuildDisplayList, rebuildOffsets } from '../state.js';

/**
 * Install the multi-level rows feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installMultiLevel(ctx) {
    ctx._multiLevelInstalled = true;

    /**
     * Toggle expansion for a given row key.
     * @param {string} key
     */
    ctx.toggleRowExpansion = (key) => {
        if (ctx.expandedRows.has(key)) {
            ctx.expandedRows.delete(key);
        } else {
            ctx.expandedRows.add(key);
        }
        rebuildDisplayList(ctx);
        rebuildOffsets(ctx);
        ctx.updateSpacer();
        ctx.visibleStart = -1;
        ctx.visibleEnd = -1;
        ctx.scheduleRender(true);
    };

    /**
     * Get the set of expanded row keys.
     * @returns {Set<string>}
     */
    ctx.getExpandedRows = () => new Set(ctx.expandedRows);

    /**
     * Remap expansion keys after row insert/reorder.
     * @param {number} idx
     * @param {number} count
     */
    ctx.remapExpandedRows = (idx, count) => {
        ctx.expandedRows = remapExpandedRows(ctx.expandedRows, idx, count);
    };
}

export default installMultiLevel;
